const query = $input.first().json.body?.query || '';
const orderMatch = query.match(/\b(\d{6})\b/);
const providedOrderId = $input.first().json.body?.order_id || null;

// Supports both n8n Cloud (Variables) and Docker (.env)
// const pineconeHost = $vars?.PINECONE_HOST || $env.PINECONE_HOST;
const pineconeHost = 'support-faq-fx69yh6.svc.aped-4627-b74a.pinecone.io' // do not include HTTPS !

return [{
  json: {
    original_query: query,
    order_id: providedOrderId || (orderMatch ? orderMatch[1] : null),
    customer_email: $input.first().json.body?.email || null,
    submission_channel: $input.first().json.body?.channel || 'API',
    timestamp: new Date().toISOString(),
    ticket_id: 'TKT-' + Date.now(),
    pinecone_host: pineconeHost
  }
}];

const preprocess = $('2. Preprocessing').first().json;
const matches = $input.first().json.matches || [];
const best = matches[0];

return [{
  json: {
    ticket_id: preprocess.ticket_id,
    order_id: null,
    status: 'resolved',
    source: 'faq',
    original_query: preprocess.original_query,
    sentiment: 'neutral',
    category: best.metadata.category || 'FAQ',
    department: 'Customer Support',
    resolution: best.metadata.answer,
    faq_question: best.metadata.question,
    faq_score: best.score,
    action_items: ['FAQ answer provided'],
    confidence_level: 'high',
    confidence_score: best.score,
    resolved_at: new Date().toISOString()
  }
}];

// Get preprocessing data directly from the Preprocessing node
const preprocess = $('2. Preprocessing').first().json;

// Get all rows from Google Sheets
const sheetRows = $('Read Google Sheet').all();

// Find matching order
const orderId = preprocess.order_id;
let orderRecord = null;
let orderHistory = null;

if (orderId && sheetRows.length > 0) {
  // Find the row where Order ID matches
  for (const row of sheetRows) {
    const rowOrderId = row.json['Order ID'];
    if (rowOrderId && String(rowOrderId).trim() === String(orderId).trim()) {
      orderRecord = row.json;
      orderHistory = row.json['Order History'] || null;
      break;
    }
  }
}

return [{
  json: {
    ...preprocess,
    order_record: orderRecord,
    order_history: orderHistory,
    has_order_context: !!orderRecord
  }
}];

const raw = $input.first().json.choices[0].message.content;
const enriched = $('3. Lookup Order History').first().json;

let parsed;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : raw);
} catch(e) {
  parsed = { sentiment: 'neutral', category: 'General Feedback', department: 'Customer Support', recognized: false, confidence: 0.3, summary: raw };
}

return [{
  json: {
    ...enriched,
    sentiment: parsed.sentiment || 'neutral',
    category: parsed.category || 'General Feedback',
    department: parsed.department || 'Customer Support',
    recognized: parsed.recognized === true,
    coordinator_confidence: parsed.confidence || 0.5,
    summary: parsed.summary || ''
  }
}];

const data = $input.first().json;
return [{
  json: {
    ticket_id: data.ticket_id,
    order_id: data.order_id,
    status: 'manual_processing',
    original_query: data.original_query,
    sentiment: data.sentiment,
    category: data.category,
    department: data.department,
    resolution: 'This request requires manual processing. Your ticket has been forwarded to our support team.',
    action_items: ['Forwarded to manual queue', 'Human review within 24h'],
    escalation_needed: true,
    escalation_reason: 'Unrecognized request',
    confidence_level: 'low',
    resolved_at: new Date().toISOString()
  }
}];

const raw = $input.first().json.choices[0].message.content;
const enriched = $('Parse Coordinator').first().json;

let parsed;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : raw);
} catch(e) {
  parsed = { response: raw, action_items: [], confidence_level: 'low', confidence_score: 0.3, escalation_needed: true, escalation_reason: 'Parse error' };
}

return [{
  json: {
    ticket_id: enriched.ticket_id,
    order_id: enriched.order_id,
    original_query: enriched.original_query,
    sentiment: enriched.sentiment,
    category: enriched.category,
    department: enriched.department,
    response: parsed.response || '',
    action_items: parsed.action_items || [],
    confidence_level: parsed.confidence_level || 'medium',
    confidence_score: parsed.confidence_score || 0.5,
    escalation_needed: parsed.escalation_needed || false,
    escalation_reason: parsed.escalation_reason || null
  }
}];

const data = $input.first().json;
return [{
  json: {
    ticket_id: data.ticket_id,
    order_id: data.order_id,
    status: 'resolved',
    original_query: data.original_query,
    sentiment: data.sentiment,
    category: data.category,
    department: data.department,
    resolution: data.response,
    action_items: data.action_items,
    confidence_level: data.confidence_level,
    confidence_score: data.confidence_score,
    resolved_at: new Date().toISOString()
  }
}];

const data = $input.first().json;
return [{
  json: {
    ticket_id: data.ticket_id,
    order_id: data.order_id,
    status: 'manual_processing',
    original_query: data.original_query,
    sentiment: data.sentiment,
    category: data.category,
    department: data.department,
    initial_response: data.response,
    resolution: 'Thank you for contacting CandleKeep. A team member will follow up shortly.',
    action_items: ['Escalated to human agent', 'Low confidence review'],
    escalation_needed: true,
    escalation_reason: data.escalation_reason || 'Low confidence',
    confidence_level: data.confidence_level,
    resolved_at: new Date().toISOString()
  }
}];
